rb_intro.cheat:
// Ruby quickstart & workflow
// Install: curl -sSL https://get.rvm.io | bash (or use rbenv/asdf)
// Create a new gem/project: bundle gem my_gem
// Run script: ruby script.rb
// REPL: irb  OR pry (gem install pry)
// Run tests: bundle exec rspec
// Format & lint: rubocop --auto-correct
// Package: gem build my_gem.gemspec && gem push <pkg>
// Useful commands: ruby -v; gem list; bundle install; bundle exec rake
// Debugging: ruby -r debug script.rb or require 'pry'; binding.pry

rb_syntax.cheat:
// Syntax & primitives cheat
// Literals: 42, 3.14, 'str', :symbol, [1,2], { a: 1 }
// Block forms: do..end (multi-line) and { } (single-line)
// Proc/lambda: p = proc { |x| x*2 } ; l = lambda { |x| x*2 }
// Strings: "#{expr}" interpolation; %q and %Q for quoting
// Safe navigation: obj&.dig(:a,:b) ; fetch: hash.fetch(:k, default)
// Freeze constants: MY_CONST = 'x'.freeze or using frozen_string_literal pragma

rb_oop.cheat:
// OOP cheat
// class Person; attr_accessor :name; def initialize(name); @name = name; end; end
// module mixin: module M; def m; 'm' end; end; class C; include M; end
// singleton method: obj.define_singleton_method(:greet){ 'hi' }
// attr_reader/attr_writer/attr_accessor shortcuts

rb_metaprogramming.cheat:
// Metaprogramming cheat
// define_method(:name){ |args| ... }
// class_eval("def dynamic; ...; end") to inject methods
// method_missing(:name, *args) for proxies but implement respond_to_missing?
// Module#prepend to wrap methods using super
// Use refinements to limit global monkey patches

rb_metaprogramming_adv.cheat:
// Advanced metaprogramming cheat
// Use refinements to scope monkey-patches
// Use method_added hook to react to new methods
// Use TracePoint for tracing calls/returns in dev only
// Use Module#prepend to wrap methods safely with super

rb_gems.cheat:
// Gems & packaging cheat
// Scaffold: bundle gem my_gem --test=rspec
// Local build: gem build my_gem.gemspec && gem install --local my_gem-0.1.0.gem
// Publish: gem push my_gem-0.1.0.gem (use API key stored in ~/.gem/credentials)
// Versioning: follow semver and update version in lib/my_gem/version.rb
// CI: build/test, gem build, gem push from CI with secure credentials
// Use gem signing and checksums for integrity where needed

rb_bundler.cheat:
// Bundler cheat
// Initialize: bundle init
// Add dependency: bundle add <gem>
// Install: bundle install --path vendor/bundle (for isolation)
// Use bundle exec <cmd> to run in bundle context
// Update: bundle update <gem>
// Check vulnerabilities: bundle audit
// CI: bundle config set --local frozen '1' && bundle install --without development test

rb_concurrency.cheat:
// Concurrency cheat
// Threads: t = Thread.new { ... } ; t.join
// Fibers: f = Fiber.new { ... } ; f.resume
// Use Thread.abort_on_exception = true in development to surface thread errors
// Sidekiq: gem 'sidekiq' ; class MyWorker; include Sidekiq::Worker; def perform(args); end; end
// Use Concurrent::Promises or async gem for structured concurrency
// Always use thread-safe data structures or mutex/synchronization when sharing state

rb_evented_io.cheat:
// Evented I/O cheat
// Use async gem: gem 'async', require 'async'
// Example: Async do |task| task.async { ... } end
// Avoid blocking: move blocking calls to thread pool (Async::Task.current.async or use Thread) or use non-blocking libs
// Use Falcon server for async Rack servers

rb_performance.cheat:
// Performance cheat
// Microbench: gem 'benchmark-ips'
// CPU sample: stackprof --mode cpu
// Allocation: stackprof --mode object or use objspace and allocation tracers
// Rails: derailed_benchmarks: bundle exec derailed bundle:mem
// Reuse buffers, freeze string literals, avoid temporary objects in hot loops

examples.code:
require 'benchmark/ips'
Benchmark.ips do |x|
  x.report('concat') { 'a' + 'b' }
  x.report('interpolate') { "#{'a'}#{'b'}" }
  x.compare!
end

rb_profiling.cheat:
// Profiling cheat
// CPU sampling: stackprof --mode cpu
// Microbench: benchmark-ips
// Flamegraphs: convert stackprof dumps to flamegraphs with tools
// Rails: use rack-mini-profiler for endpoint sampling
// Always profile real workloads and not just synthetic loops

rb_c_extensions.cheat:
// Native extensions cheat
// mkmf extconf.rb: require 'mkmf'; create_makefile('my_ext')
// Build: ruby extconf.rb && make
// FFI: gem 'ffi'; FFI::Library; ffi_lib 'c'
// Use rake-compiler for cross-platform packaging
// Document native deps (libssl-dev, libpq-dev) and test builds in CI containers

rb_wasm.cheat:
// WASM cheat
// Compile Rust to WASM: use wasm-pack for JS targets or wasm32-unknown-unknown for WASM binary
// For Ruby server, consider calling WASM via native binding or run WASM module inside a separate service and call via HTTP
// Use Wasmtime or Wasmer for embedding WASM in native apps

rb_testing.cheat:
// Testing cheat
// RSpec init: rspec --init
// Run: bundle exec rspec
// Use FactoryBot: factory_girl syntax; create(:user)
// HTTP stubs: gem 'webmock' or 'vcr'
// Coverage: gem 'simplecov' and enable in spec_helper

rb_tooling.cheat:
// Tooling cheat
// rubocop --auto-correct
// brakeman for Rails security: brakeman -A
// bundle-audit: bundle audit check --update
// CI: run rubocop, rspec, brakeman, bundle-audit in pipeline
// Pre-commit hooks: Overcommit or simple git hooks to run quick checks

rb_sorbet.cheat:
// Sorbet cheat
// Install: gem 'sorbet', gem 'sorbet-runtime'
// Init: srb init
// Add signature: sig { params(x: Integer).returns(String) }
// Run: srb tc
// Use sorbet-runtime to check at runtime: include RBuiltins or require 'sorbet-runtime'

rb_steep.cheat:
// Steep cheat
// Install: gem 'steep'
// Init: steep init
// Write .rbs files under sig/ or types/
// Run: steep check
// Use type annotations to verify without runtime cost

rb_debugging.cheat:
// Debugging cheat
// Install: gem install pry pry-byebug
// Use: require 'pry'; binding.pry to pause and inspect
// Step-through: byebug or debug gem for line-by-line stepping
// Capture backtrace: exception.backtrace or use tools like Sentry for production
// Use logging with request IDs for correlation in production

rb_deployment.cheat:
// Deployment cheat
// Dockerfile multi-stage: build deps in builder stage and copy only runtime files to final image
// Run server: bundle exec puma -C config/puma.rb
// Graceful shutdown: trap SIGTERM and finish requests before exit
// CI: build, test, tag and push image; deploy with rolling updates
// Secrets: use secret manager (Vault, K8s secrets, cloud secret manager)

rb_db.cheat:
// DB & ActiveRecord cheat
// Eager load: Model.includes(:assoc).where(...)
// Batch process: Model.find_each(batch_size: 100) { |r| do_work(r) }
// Use transaction: ActiveRecord::Base.transaction { ... }
// Use prepared queries to avoid injection: where('id = ?', id)
// Index: add_index :table, :column, name: 'index_name'

examples.code:
Post.includes(:comments).where(published: true).limit(20)
# use find_each for large scopes
Post.where(active: true).find_each(batch_size: 100) { |p| process(p) }

rb_graphql.cheat:
// GraphQL-Ruby cheat
// Schema: class MySchema < GraphQL::Schema
// Use batch loading: Loaders::RecordLoader.for(Model).load(id)
// Validate: use input types and custom scalars
// Protect: limit depth and complexity, enable query whitelisting if needed

rb_security.cheat:
// Security cheat
// Use parameterized queries: where('email = ?', email)
// Escape HTML in views: use helpers (sanitize, h) or safe templates
// Enable CSP headers via middleware/config
// Use Brakeman: brakeman -A to scan Rails apps
// Rotate secrets and store in vault/secret manager

rb_cli.cheat:
// CLI cheat
// Thor: gem 'thor' ; class CLI < Thor; desc 'hello NAME', 'Say hello'; def hello(name); puts "Hello #{name}"; end; end
// Optparse for simple flags: require 'optparse'
// Testing CLIs: use Aruba or call command classes directly in unit tests
